Функция ПолучитьСуммовыйДолгКонтрагента(СсылкаНаКонтрагента)

    // Создаём запрос для получения суммы положительных остатков по договорам контрагента
    Запрос = Новый Запрос;
    Запрос.Текст = "
        |SELECT
        |    СУММА(ВН.Сумма) КАК СуммаДолга
        |FROM
        |    РегистрНакопления.Взаиморасчеты КАК ВН
        |    ВН.Договор.Владелец КАК ДоговорВладелец
        |ГДЕ
        |    ДоговорВладелец = &Контрагент
        |    И ВН.Сумма > 0";

    Запрос.УстановитьПараметр("Контрагент", СсылкаНаКонтрагента);

    Результат = Запрос.Выполнить();
    Выборка = Результат.Выбрать();

    Если Выборка.Следующий() Тогда
        Если Не Значение(Выборка.СуммаДолга) Тогда
            Возврат 0;
        Иначе
            Возврат Выборка.СуммаДолга;
        КонецЕсли;
    Иначе
        Возврат 0;
    КонецЕсли;

КонецФункции
